import * as React from 'react';

import * as SwitchPrimitive from '@radix-ui/react-switch';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';

/**
 * Size math derived from:
 * https://github.com/radix-ui/themes/blob/c508125ad71cc0425fe40c87af9c88991e0b4080/packages/radix-ui-themes/src/components/switch.css
 *
 * Formula:
 *   - Root height = root width / 1.75
 *   - Thumb size = root width / 2
 */
const switchVariants = cva(
  [
    'peer inline-flex h-[1.15rem] w-8 shrink-0 items-center p-0',
    'rounded-full border border-transparent outline-none',
    'transition-all',
    'focus-visible:outline-none focus-visible:ring-2',
    'disabled:cursor-not-allowed disabled:opacity-50',
    'data-[state=checked]:bg-primary data-[state=unchecked]:bg-input',
  ],
  {
    variants: {
      size: {
        sm: 'h-[0.86rem] w-6',
        md: 'h-[1.15rem] w-8',
        lg: 'h-[1.44rem] w-10',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

const switchThumbVariants = cva(
  [
    'pointer-events-none block size-4 rounded-full bg-background ring-0',
    'transition-transform',
    'data-[state=checked]:translate-x-[calc(100%-2px)]',
    'data-[state=unchecked]:translate-x-0',
  ],
  {
    variants: {
      size: {
        sm: 'size-3',
        md: 'size-4',
        lg: 'size-5',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

/**
 * A control that allows the user to toggle between checked and not checked.
 */
function Switch({
  className,
  size = 'md',
  ...props
}: React.ComponentProps<typeof SwitchPrimitive.Root> &
  VariantProps<typeof switchVariants>) {
  return (
    <SwitchPrimitive.Root
      data-slot="switch"
      className={cn(switchVariants({ size }), className)}
      {...props}
    >
      <SwitchPrimitive.Thumb
        data-slot="switch-thumb"
        className={cn(switchThumbVariants({ size }))}
      />
    </SwitchPrimitive.Root>
  );
}

export { Switch };
